import base64
import json
import re
from xml.dom import minidom
from fastapi import FastAPI, HTTPException, Header, Depends
from pydantic import BaseModel

app = FastAPI()

# ================= CẤU HÌNH BẢO MẬT =================
MODEL_B64 = ''

API_SECRET_KEY = "giaiautocaptchabydvfast" # Thay bằng key tùy ý

# ================= MÔ HÌNH DỮ LIỆU =================
class CaptchaRequest(BaseModel):
    svg_data: str

# Hàm kiểm tra Key
async def verify_token(x_api_key: str = Header(None)):
    if x_api_key != API_SECRET_KEY:
        raise HTTPException(status_code=403, detail="Key bảo mật không hợp lệ!")
    return x_api_key

# ================= LOGIC GIẢI MÃ =================
def parse_svg_captcha(svg_string: str):
    try:
        parsed_model = json.loads(base64.b64decode(MODEL_B64).decode('utf-8'))
        element = minidom.parseString(svg_string)
        paths = element.getElementsByTagName("path")
        nostroke_paths = [path for path in paths if not path.getAttribute('stroke')]
        
        vals = []
        for p in nostroke_paths:
            d_attr = p.getAttribute("d")
            x_val = int(d_attr.split(".")[0].replace("M", ""))
            vals.append(x_val)
            
        sorted_vals = sorted(vals)
        solution = [""] * len(nostroke_paths)
        
        for i, path in enumerate(nostroke_paths):
            d_attr = path.getAttribute('d')
            pattern = re.sub(r'[\d.\s]+', '', d_attr)
            char_value = parsed_model.get(pattern, "?")
            correct_index = sorted_vals.index(vals[i])
            solution[correct_index] = char_value

        return "".join(solution)[:4]
    except:
        return None

# ================= ENDPOINT =================
@app.post("/decrypt", dependencies=[Depends(verify_token)])
async def decrypt_captcha(item: CaptchaRequest):
    """
    API giải mã - Bắt buộc có Header 'x-api-key'
    """
    result = parse_svg_captcha(item.svg_data)
    if result:
        return {"status": "success", "result": result}
    return {"status": "error", "message": "Giải mã thất bại"}

if __name__ == "__main__":
    import uvicorn
    import os
    # Lấy port từ hệ thống của Render, nếu không có thì mặc định là 8000
    port = int(os.environ.get("PORT", 8000))
    uvicorn.run(app, host="0.0.0.0", port=port)